public static long solve(long n, long[][] edges, long k) {
    long low = 0;
    long high = 0;
    for (long[] edge : edges) {
        if (edge[2] > high) {
            high = edge[2];
        }
    }
    long ans = high;
    while (low <= high) {
        long mid = low + (high - low) / 2;
        if (feasible(n, edges, k, mid)) {
            ans = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }
    return ans;
}

private static boolean feasible(long nLong, long[][] edges, long k, long x) {
    int n = (int) nLong;
    int[] parent = new int[n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    for (long[] edge : edges) {
        long weight = edge[2];
        if (weight <= x) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int ru = find(parent, u);
            int rv = find(parent, v);
            if (ru != rv) {
                parent[ru] = rv;
            }
        }
    }

    int comp = 0;
    for (int i = 0; i < n; i++) {
        if (parent[i] == i) {
            comp++;
        }
    }

    return comp <= k;
}

private static int find(int[] parent, int x) {
    if (parent[x] != x) {
        parent[x] = find(parent, parent[x]);
    }
    return parent[x];
}
