public static long solve(long n, long[][] edges, long k) {
    int N = (int) n;
    long max_weight = 0;
    for (long[] edge : edges) {
        if (edge[2] > max_weight) 
            max_weight = edge[2];
    }
    long low = 0;
    long high = max_weight;
    while (low < high) {
        long mid = (low + high) / 2;
        if (valid(N, edges, mid, (int) k)) {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    return low;
}

private static boolean valid(int n, long[][] edges, long X, int k) {
    int[] parent = new int[n];
    int[] rank = new int[n];
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }
    int count = n;
    for (long[] edge : edges) {
        if (edge[2] <= X) {
            int u = (int) edge[0];
            int v = (int) edge[1];
            int ru = find(u, parent);
            int rv = find(v, parent);
            if (ru != rv) {
                if (rank[ru] < rank[rv]) {
                    parent[ru] = rv;
                } else if (rank[rv] < rank[ru]) {
                    parent[rv] = ru;
                } else {
                    parent[rv] = ru;
                    rank[ru]++;
                }
                count--;
            }
        }
    }
    return count <= k;
}

private static int find(int x, int[] parent) {
    int root = x;
    while (root != parent[root]) {
        root = parent[root];
    }
    int curr = x;
    while (curr != root) {
        int next = parent[curr];
        parent[curr] = root;
        curr = next;
    }
    return root;
}
